data = str2num(out); if data&amp;gt;-2 &amp;amp; data &amp;lt; 2 %detect if data is legal % disp(&amp;#39;*******data comes! \n&amp;#39;); t=[t 0.01*2*pi*i]; %0 0.1 0.2 0.3.. %Matrix 1*(i+1), column is increasing m=[m data]; %Matrix 2*(i+1), 2row, i+1 column. %http://blog.csdn.net/sonictl %set(p(1),&amp;#39;XData&amp;#39;,t,&amp;#39;YData&amp;#39;,m(1,:)) %set(p(2),&amp;#39;XData&amp;#39;,t,&amp;#39;YData&amp;#39;,m(2,:)) set(p,&amp;#39;XData&amp;#39;,t,&amp;#39;YData&amp;#39;,m(1,:)) %http://blog.csdn.net/sonictl drawnow x = x + 3.6/360*2*pi; % x = x+0.
